-- ── nefarious ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$nefarious is a free, open source, self-hosted web application that automatically searches for and downloads movies and TV shows by combining Jackett torrent search with Transmission-based download management.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$nefarious Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$nefarious review 2026: the free, open source self-hosted movie and TV download automation tool combining Jackett and Transmission, features and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$nefarious is a free, open source, self-hosted web application maintained on GitHub under the account lardbit (github.com/lardbit/nefarious) that automates the process of finding and downloading movies and television shows. It sits within the well-known self-hosted \"*arr\" media automation ecosystem alongside tools like Sonarr, Radarr, and Ombi, and its explicit design goal is to combine the functionality of those three separate applications into a single tool: Sonarr-like TV show tracking and season/episode management, Radarr-like movie tracking, and Ombi-like user request management, all in one interface. Architecturally, nefarious does not perform torrent indexing or downloading itself; instead it orchestrates two other well-established self-hosted tools under the hood, using Jackett as its torrent indexer/search aggregator to query configured torrent trackers, and Transmission as the BitTorrent client that actually performs the download once a release is selected. The application is distributed primarily as a Docker image (lardbit/nefarious on Docker Hub) and is typically deployed as part of a broader self-hosted media stack alongside a media server such as Plex, Jellyfin, or Emby, and often behind a VPN for privacy during torrenting. Because it is a community-maintained open source project rather than a commercial company, there is no founding company, headquarters, employee count, or funding history to report, and pricing is not applicable beyond the cost of the user's own server infrastructure; the software itself carries no license fee. Key functional features include configurable quality profiles that let users define preferred resolution and codec targets for automatic downloads, user-defined keyword filtering to include or exclude specific release groups or terms from search results, support for multiple user accounts with permission groups so a household or shared server can allow different levels of access, a \"wanted\" and watch-list system for tracking desired content, and broad notification support through the Apprise library, which lets nefarious send alerts to services such as Discord, Slack, Pushover, and dozens of other notification platforms when downloads complete or fail. The target audience is home-lab operators, self-hosting enthusiasts, and \"data hoarders\" who want to consolidate movie and TV request-and-download automation into a single tool rather than running Sonarr, Radarr, and Ombi as three separate services, often to reduce the resource footprint or administrative overhead of maintaining a full arr-stack on modest hardware like a home server, NAS, or single-board computer. Its direct competitors and alternatives are the individual, more actively maintained tools it was designed to replace or combine, Sonarr and Radarr for tracking and downloading, and Ombi, Overseerr, Jellyseerr, or the newer unified Seerr project for user-facing request management, as well as other combined or lightweight alternatives within the awesome-arr community list of self-hosted media tools. Compared to those more specialized, individually maintained projects, nefarious's main trade-off is consolidation and simplicity at the cost of a smaller contributor community, less frequent updates, and a less polished interface than the dedicated, purpose-built alternatives it draws inspiration from.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '83b24c52-88dd-4d43-8826-92e123f63cae';

