-- ── Neko ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Neko is an open source, self-hosted virtual browser and desktop-streaming platform that runs in Docker and uses WebRTC to let multiple users watch, browse, and collaborate together in real time.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Neko Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Neko review 2026: the open source, self-hosted virtual browser streamed over WebRTC in Docker, its features, use cases, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Neko, also referred to as n.eko, is an open source, self-hosted virtual browser and desktop-streaming platform created by developer m1k1o, built to run inside a Docker container and stream an interactive session to multiple simultaneous viewers using WebRTC. The project's origin traces back to the shutdown of rabb.it, a co-browsing and watch-party service that went under after failing to secure further venture funding; m1k1o, working with an earlier developer known as nurdism, built Neko as a self-hosted replacement after finding existing alternatives incomplete and finding that consumer tools like Discord screen share were unreliable for group video-watching sessions over slower internet connections. The name Neko is the Japanese word for cat. Technically, Neko is not limited to streaming just a web browser; because it runs a full Linux desktop environment inside its Docker container, it can stream any Linux-compatible application, including media players like VLC, meaning the same platform can be used for group video watch parties, not solely for web browsing. WebRTC is used as the streaming transport to deliver near real-time video with reported latency under roughly 300 milliseconds, with synchronized audio and support for hardware-accelerated encoding to improve performance on capable servers. Because Neko is fully open source with no company behind it, there is no founding date, headquarters, employee count, or funding history to report, and there is no commercial pricing model: the software is free to download, self-host, and modify, distributed via Docker images (m1k1o/neko on Docker Hub) and deployable on any infrastructure that supports Docker, including AWS, Azure, Google Cloud, and other cloud or on-premises environments, with optimized builds available for low-power ARM hardware such as the Raspberry Pi. The broader Neko ecosystem includes companion projects such as neko-rooms, a self-hosted room-management layer that lets an operator spin up and manage multiple isolated Neko sessions or \"rooms\" for different groups of users. Neko's primary use cases include hosting virtual watch parties and shared media viewing sessions, running remote presentations, enabling co-browsing and real-time collaborative debugging or research sessions, and providing sandboxed remote-support or teaching environments where an instructor can share full interactive control of a browser or desktop rather than a passive screen share. Its target audience is self-hosting enthusiasts, privacy-conscious friend groups seeking a rabb.it-style shared viewing experience, remote teams needing collaborative browsing tools, and technical users building sandboxed browsing environments for research, automation, or security testing. Neko's competitors and adjacent tools include commercial co-watching services like Teleparty (formerly Netflix Party) and Kosmi, other self-hosted remote-browser projects, and general remote-desktop tools like Apache Guacamole or noVNC, though Neko differentiates itself specifically through its low-latency WebRTC streaming (versus VNC-based alternatives which typically have higher latency) and its container-native, easily scriptable Docker deployment model that appeals to the self-hosted and home-lab community.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e9197c5d-03b9-4574-a2ba-90f4d26880a9';

