-- ── Neon ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Neon is a serverless Postgres database platform that separates storage and compute, enabling instant database branching, autoscaling, and scale-to-zero, and was acquired by Databricks in 2025.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Neon Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Neon review 2026: serverless Postgres pricing, branching and autoscaling features, the Databricks acquisition, and top alternatives for developers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Neon is a serverless Postgres database platform founded in 2021 by CEO Nikita Shamgunov alongside co-founders Heikki Linnakangas and Stas Kelvich, both experienced Postgres core contributors, with Shamgunov previously known as co-founder and CEO of the database company SingleStore, which he grew to more than 100 million dollars in annual revenue before starting Neon. The company is headquartered in San Francisco, California, and grew to roughly 150 or more employees prior to its acquisition. Neon raised a total of approximately 130.6 million dollars in venture funding over its life as an independent company, with investors including Microsoft's venture arm M12, General Catalyst, Menlo Ventures, and Notable Capital; its most recent independent round was a 25.6 million dollar strategic investment led by M12 in August 2024. In May 2025, Databricks announced it would acquire Neon in a deal reported at approximately 1 billion dollars, aiming to combine Neon's serverless Postgres technology with Databricks' data and AI platform to better serve developers and AI agents that need to provision and manage databases programmatically; the deal was expected to close by July 31, 2025. Architecturally, Neon's defining innovation is separating storage and compute in Postgres: its multi-tenant storage engine (whose core is open source) decouples the traditional Postgres write-ahead log and page cache from a stateless compute layer, which enables features unusual for a Postgres provider, including instant, copy-on-write database branching (creating a full, isolated copy of a database in seconds without duplicating storage), autoscaling of compute resources up and down based on load, and scale-to-zero, where compute is automatically suspended after a period of inactivity (roughly five minutes) so users pay nothing for idle databases, with the database resuming in a few hundred milliseconds when a new query arrives. Neon's pricing is consumption-based: a Free plan includes 100 CU-hours per month, 0.5 GB of storage, and autoscaling up to 2 compute units (a compute unit equals 1 vCPU and 4 GB of RAM), suitable for side projects and development; the Launch plan charges 0.106 dollars per CU-hour with autoscaling up to 8 CU and no free-tier limits, aimed at startups and growing teams; the Scale plan charges 0.222 dollars per CU-hour and adds a 99.95 percent uptime SLA, HIPAA eligibility, SOC 2 compliance, Private Link, and SSO at no added monthly fee, targeting production workloads; and a custom-priced Business/Enterprise plan offers dedicated infrastructure and premium support for large-scale deployments. Storage on paid plans is billed at a flat 0.35 dollars per GB-month, and Neon removed its previous 5 dollar monthly minimum spend, making paid plans purely usage-based. Neon's target audience is software developers and engineering teams building on Postgres who want git-like database branching for testing and CI/CD, instant provisioning for ephemeral environments, and cost efficiency for spiky or intermittent workloads, as well as, increasingly, AI agent platforms that need to programmatically spin up isolated databases on demand. Its primary competitors include Supabase (which also offers a Postgres-based backend platform), PlanetScale (MySQL-focused serverless database), Amazon Aurora Serverless, CockroachDB, and traditional managed Postgres offerings from AWS RDS, Google Cloud SQL, and Azure Database for PostgreSQL.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cf2565ff-7160-42e9-8d6c-efdb9830004d';

