-- ── Neos ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Neos is an open source PHP content application platform, built on the Flow framework, known for live in-place content editing and flexible content modeling for enterprise websites.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Hamburg, Germany (Neos Foundation)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Neos CMS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Neos CMS review 2026: the free, open source PHP content platform with live editing and flexible content modeling, features, licensing, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Neos is an open source content application platform built in PHP on top of the Flow framework, aimed at enterprise websites, digital agencies, and developers who need sophisticated content modeling combined with an intuitive, live in-place editing experience. Its origins trace back to 2006, when development began within the TYPO3 community; in 2007 developers Robert Lemke and Karsten Dambekalns began working full-time on what was originally intended to be a completely modernized version 5.0 of TYPO3, successively codenamed TYPO3 Phoenix and then TYPO3 Neos. In 2015, the TYPO3 Association and the Neos team agreed to separate, with Neos continuing development outside the TYPO3 Association's umbrella, and in 2017 the Neos Foundation was formally established as a UK-based Community Interest Company (CIC) dedicated to promoting the ongoing development of Neos and supporting its open source community; German web agency sitegeist, among others, is a prominent contributor and service provider within the Neos ecosystem. Neos and its core repositories, including neos/neos and neos/neos-development-collection, are released under the GNU General Public License version 3 (GPL-3.0), making the software free to use, modify, and redistribute, with no purchase price for the core software itself. As a community-governed open source foundation project rather than a single venture-backed company, Neos has no centralized headquarters, employee count, or funding round history in the traditional startup sense; instead, its ecosystem is sustained by a network of independent agencies and freelance developers (organized loosely as \"Neos service providers\" listed on neos.io) who build revenue through implementation, customization, hosting, and support services layered on top of the free core software, similar in structure to other foundation-governed open source CMS projects like Drupal or TYPO3 itself. Neos's defining technical differentiator is its content editing philosophy: rather than presenting editors with a generic backend form interface disconnected from the final page layout, Neos lets content editors work directly within a live, WYSIWYG-style preview of the actual page, editing text, media, and structured content components in place while the underlying system maintains a structured, strongly typed content repository suitable for omnichannel and headless delivery. The platform is built around Neos Flow (an MVC PHP framework providing dependency injection, aspect-oriented programming, and a robust security framework), the Neos Content Repository (a node-based, versioned content storage layer), and Fusion (Neos's own declarative rendering and templating language), giving developers fine-grained control over how structured content is composed and rendered across different channels. Neos targets mid-sized to large organizations, digital agencies, and public-sector or enterprise clients (particularly common in the German-speaking DACH region, reflecting its TYPO3 heritage) that need a highly customizable, developer-friendly CMS without vendor lock-in or recurring license fees, and that value in-place editing UX for non-technical content teams. Its primary competitors and alternatives include other open source PHP and enterprise CMS platforms such as TYPO3, Drupal, and WordPress (particularly with the Gutenberg block editor), as well as headless-first platforms like Contentful, Storyblok, and Sanity, with Neos differentiating itself through the combination of true in-place visual editing and a strongly structured, headless-capable content repository underneath.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fe036b27-0ca6-4aa1-8287-c9d8dafd6b57';

